/*
* Create an element with given info.
* Parameters:
*      iLoc		location for the new element
*		form[]		forming MYPOINTs
*      cen			center of the circumsphere
*		rad			square of the radius of the circumsphere
* Result:
*      the size of the array of elements
*/
INTEGER DTIso3D::crtEle(INTEGER iLoc, INTEGER form[], MYPOINT cen, REAL rad)
{
	int i;
	Elem* pElem = &m_pElems[iLoc];

	for (i = 0; i <= DIM; i++)
	{
		(pElem->form)[i] = form[i];
		(pElem->neig)[i] = NULL_NEIG;
	}
	for (i = 0; i < DIM; i++)
	{
		(pElem->cen)[i] = cen[i];
	}
	pElem->rad = rad;
	pElem->iReserved = 0;
	pElem->iReserved2 = 0;

	m_vecNewEles.push_back(iLoc);
	return 1;
}

/*
* Recover the new elements to their INITial states
* Parameters:
*     void
* Result:
*     the size of the array of new elements
* Notes:
*     1. The function is called if an error happens while inserting ia node
*     2. All new elements is flagged as deleted in the recovery
*     3. As m_nAftTail records the number of elements whose positions are
*        taken from the tail of the array of elements rather than the
*        the empty locations formed by previous deleted elements, the m_nElems
*        should subtract m_nAftTail in the recoverry if m_nAftTail > 0
*/
int DTIso3D::recoverNewEles()
{
#if 0
	int i, size = m_vecNewEles.size();
	INTEGER iEle;
	for (i = 0; i < size; i++)
	{
		iEle = m_vecNewEles[i];
		m_pElems[iEle].rad = -999.0;
		m_pElems[iEle].iReserved = 0;
	}

	if (m_nAftTail > 0)
		m_nElems -= m_nAftTail;

	return size;
#endif
	int i, size = m_vecNewEles.size();
	INTEGER iEle;
	for (i = 0; i < size; i++)
	{
		iEle = m_vecNewEles[i];
		setDeleted(iEle);
		m_pElems[iEle].iReserved = 0;
	}

#ifdef _ONE_LONG_ARRAY
	if (m_nAftTail > 0)
		m_nElems -= m_nAftTail;
#else
	if (m_nAftTail > 0)
		m_pElems.setArraySize(m_pElems.getArraySize() - m_nAftTail);
#endif

	return size;
}

/*
* Clear the array of new elements & reset m_nAftTail as 0
* Parameters:
*    void
* Result
*    the size of the array of new elements before clearing it
*/
int DTIso3D::clrNewEles()
{
	int size = m_vecNewEles.size();
	m_nAftTail = 0;
	m_vecNewEles.clear();

	return size;
}

int DTIso3D::addNewCreEles()
{
	int i, size = m_vecNewEles.size();

	/* -----------------------------------------------
	* 注意：m_vecNewCreEles是以叠加的方式增加单元的
	* 不要清空它
	* ---------------------------------------------*/
	for (i = 0; i < size; i++)
	{
		m_vecNewCreEles.push_back(m_vecNewEles[i]);
	}

	return m_vecNewCreEles.size();
}

