int DTIso3D::writePL3_Subset_Global(const char* fname, int elems[], int nElems)
{
	FILE* fp = fopen(fname, "w");
	INTEGER i, j = 0;
	MYPOINT pnt;
#ifdef _ONE_LONG_ARRAY
	INTEGER nodeSize = m_nNodes;
#else
	INTEGER nodeSize = m_pNodes.getArraySize();
#endif

	fprintf(fp, "%d %d %d\n", nElems, nodeSize, 0);

	for (i = 0; i < nodeSize; i++)
	{
		this->nToW(m_pNodes[i].pt, &pnt);
		fprintf(fp, "%d %14.14lf %14.14lf %14.14lf\n", i + 1,
			pnt[0], pnt[1], pnt[2]);
	}

	for (j = 0; j < nElems; j++)
	{
		i = elems[j];
		fprintf(fp, "%d %d %d %d %d\n", i + 1,
			(m_pElems[i].form)[0] + 1, (m_pElems[i].form)[1] + 1,
			(m_pElems[i].form)[2] + 1, (m_pElems[i].form)[3] + 1);
	}

	fclose(fp);

	return 0;
}

