#else
/* -------------------------------------------------------------------------------
 * 注意：这个函数只适用于内部网格边
 * ---------------------------------------------------------------------------- */
int DTIso3D::findShell(INTEGER s, INTEGER e, Shell she, int* nShe, INTEGER* iHint)
{
	INTEGER iElem, iSrch, * pElemF, * pElemN, * pSrchF;
	Elem* pElem, * pSrch;
	int cnt = 0, m, mm, j, kIdx, kkIdx;
	INTEGER iFir;
	INTEGER idx[4], iNode, iThird, iiThird;
	int iidx[4];

	*nShe = 0;
#ifdef _TEST
#ifdef _ONE_LONG_ARRAY
	assert(s >= 0 && s < m_nNodes);
	assert(e >= 0 && e < m_nNodes);
#else
	assert(s >= 0 && s < m_pNodes.getArraySize());
	assert(e >= 0 && e < m_pNodes.getArraySize());
#endif
#endif /* _TEST  */
	iFir = iHint ? *iHint : m_pNodes[s].iReserved; /* iHint为nullptr时，查询哈希表  */
	pElem = &m_pElems[iFir];
	pElemF = pElem->form;
	if (pElemF[0] == e || pElemF[1] == e || pElemF[2] == e || pElemF[3] == e)
		she[cnt++] = iFir;
	else
	{
		for (kIdx = 0; kIdx <= DIM; kIdx++)
			if (pElemF[kIdx] == s)
				break;

		addTreeSearch((iFir << 2) | kIdx);
		addTstEle(iFir, pElem);
		while (!isTreeSearchEmpty())
		{
			iElem = pickTreeSearch();
			kIdx = iElem & 0x3;
			iElem = iElem >> 2;
			pElem = &m_pElems[iElem];
			pElemN = pElem->neig;
			for (m = 0; m <= DIM; m++)
			{
				if (m == kIdx)
					continue;

				iSrch = pElemN[m];
				if (iSrch != NULL_NEIG && !isTstEle(pSrch = &m_pElems[iSrch]))
				{/* must include s  */
					pSrchF = pSrch->form;

					if (pSrchF[0] == e || pSrchF[1] == e || pSrchF[2] == e || pSrchF[3] == e)
					{
						she[cnt++] = iSrch;
						break;
					}
					for (mm = 0; mm <= DIM; mm++)
					{
						if (pSrchF[mm] == s)
							kkIdx = mm;
					}
					addTreeSearch((iSrch << 2) | kkIdx);
					addTstEle(iSrch, pSrch);
				}
			}
			if (m <= DIM)
			{
				clrTreeSearEles();
				break;
			}
		}

		clrTstEles();
	}

	if (cnt != 1)
		return 0;

	if (cnt == 1)
	{
		pElem = &m_pElems[she[0]];
		pElemF = pElem->form;
		for (m = 0, j = 0; m <= DIM; m++)
		{
			iNode = pElemF[m];
			if (iNode != s && iNode != e)
			{
				idx[j] = iNode;
				iidx[j++] = m;
			}
		}
		assert(j == 2);

		iSrch = pElem->neig[iidx[0]];
		iThird = idx[1];
		while (iSrch != she[0] && iSrch != NULL_NEIG)
		{
			if (cnt >= MAX_SHELL_SIZE)
			{
				printf("Increase MAX_SPHERE_SIZE(%d), please.\n", MAX_SHELL_SIZE);
				throw EXCEPTIONSTRING(std::string("MAX_SPHERE_SIZE is too small !"));;
			}
			she[cnt++] = iSrch;
			pElem = &m_pElems[iSrch];
			for (m = 0; m <= DIM; m++)
			{
				iNode = pElem->form[m];
				if (iNode == iThird)
					iSrch = pElem->neig[m];
				else if (iNode != s && pElem->form[m] != e)
					iiThird = m;
			}
			assert(iiThird >= 0);
			iThird = pElem->form[iiThird];
		}

		if (iSrch != she[0])
		{/* 这是一条边界边  */
			iSrch = pElem->neig[iidx[1]];
			iThird = idx[0];
			while (iSrch != she[0] && iSrch != NULL_NEIG)
			{
				if (cnt >= MAX_SPHERE_SIZE)
				{
					printf("Increase MAX_SPHERE_SIZE(%d), please.\n", MAX_SPHERE_SIZE);
					throw EXCEPTIONSTRING(std::string("MAX_SPHERE_SIZE is too small !"));;
				}
				she[cnt++] = iSrch;
				pElem = &m_pElems[iSrch];
				for (m = 0, iiThird = -1; m <= DIM; m++)
				{
					iNode = pElem->form[m];
					if (iNode == iThird)
						iSrch = pElem->neig[m];
					else if (iNode != s && pElem->form[m] != e)
						iiThird = m;
				}
				assert(iiThird >= 0);
				iThird = pElem->form[iiThird];
			}
		}
	}

	*nShe = cnt;

	return cnt;
}
