			if (m_nMaxInflationLevel >= 0)
			{
				nodeIndices[2] = -1;
				m_listBndIntEnts.nodeIndices(iEntGlobal, nodeIndices);
				printf("%-4d--%s(%-4d;%-4d;%-4d);#SPs:%-3d.\n", iEntGlobal, nodeIndices[2] >= 0 ? "FACE" : "EDGE",
					nodeIndices[0], nodeIndices[1], nodeIndices[2], m_listBndIntEnts.entCounter(iEntGlobal));
			}
