bool DTIso3D::isCaviBondOverset(INTEGER iCaviE, INTEGER iCode)
{
	if (!(iCaviE >= 0 && iCaviE < m_nElems) || !(iCode >= 0 && iCode <= DIM))
		return false;
	assert(iCaviE >= 0 && iCaviE < m_nElems && iCode >= 0 && iCode <= DIM);
	return m_pElems[iCaviE].iReserved2 & (1 << (5 + iCode * 2));
}

void DTIso3D::flagCaviBond(INTEGER iCaviE, INTEGER iCode, INTEGER flag)
{
	assert(iCaviE >= 0 && iCaviE < m_nElems);
	flag == 0 ? (m_pElems[iCaviE].iReserved2 &= ~(1 << (4 + iCode * 2))) :
		(m_pElems[iCaviE].iReserved2 |= (1 << (4 + iCode * 2)));
}

void DTIso3D::flagCaviBondOverset(INTEGER iCaviE, INTEGER iCode, INTEGER flag)
{
	assert(iCaviE >= 0 && iCaviE < m_nElems);
	flag == 0 ? (m_pElems[iCaviE].iReserved2 &= ~(1 << (5 + iCode * 2))) :
		(m_pElems[iCaviE].iReserved2 |= (1 << (5 + iCode * 2)));
}

