void DTIso3D::delCaviBond(INTEGER iCaviE, INTEGER iCode)
{
	INTEGER l, i1;
	const int fcn[4][4] =
	{
		{1, 2, 3, 0},
		{2, 0, 3, 1},
		{0, 1, 3, 2},
		{1, 0, 2, 3}
	};

	/* --------------------------------------------------------------
	* 预防重复删除
	* ------------------------------------------------------------- */
	if (!isCaviBond(iCaviE, iCode))
		return;

	/* --------------------------------------------------------------
	* 标志空腔边界为删除状态
	* ------------------------------------------------------------- */
	flagCaviBond(iCaviE, iCode, 0);

	/* --------------------------------------------------------------
	* 当一条空腔边界消失时，其对应顶点的引用也相应的需要减少1
	* ------------------------------------------------------------- */
	for (l = 0; l < DIM; l++)
	{
		i1 = m_pElems[iCaviE].form[fcn[iCode][l]];
		if (minusCaviBondNodeRef(i1) <= 0)
		{
			m_nDistinctB--;
		}
	}
}

void DTIso3D::addCaviBond(INTEGER iCaviE, INTEGER iCode)
{
	INTEGER l, i1;
	CaviBnd caviBond;

	const int fcn[4][4] =
	{
		{1, 2, 3, 0},
		{2, 0, 3, 1},
		{0, 1, 3, 2},
		{1, 0, 2, 3}
	};

	/* --------------------------------------------------------------
	* 预防重复增加
	* ------------------------------------------------------------- */
	if (isCaviBond(iCaviE, iCode))
		return;

	/* --------------------------------------------------------------
	* 标志空腔边界为激活状态
	* ------------------------------------------------------------- */
	flagCaviBond(iCaviE, iCode, 1);

	if (!isCaviBondOverset(iCaviE, iCode))
	{
		memset(&caviBond, 0, sizeof(caviBond));
		caviBond.iElem = iCaviE;
		caviBond.iCode = iCode;

		m_vecCaviBonds.push_back(caviBond);
		flagCaviBondOverset(iCaviE, iCode, 1);
	}

	/* --------------------------------------------------------------
	* 当增加一条空腔边界时，其对应顶点的引用也相应的需要增加1
	* ------------------------------------------------------------- */
	for (l = 0; l < DIM; l++)
	{
		i1 = m_pElems[iCaviE].form[fcn[iCode][l]];
		if (plusCaviBondNodeRef(i1) == 1)
		{
			m_nDistinctB++;
		}
	}
}

int DTIso3D::getCaviEdge(INTEGER iNod1, INTEGER iNod2)
{
	INTEGER temp;
	INTEGER hashIt;

	if (iNod1 > iNod2)
	{
		temp = iNod1;
		iNod1 = iNod2;
		iNod2 = temp;
	}

	hashIt = m_pCaviEdgeHash[iNod1];
	while (hashIt > 0)
	{
		assert(hashIt < m_vecCaviEdges.size());
		if (m_vecCaviEdges[hashIt].iEnd == iNod2)
			return hashIt;

		hashIt = m_vecCaviEdges[hashIt].hashNxt;
	}

	return -1;
}

int DTIso3D::addCaviEdge(INTEGER iNod1, INTEGER iNod2)
{
	INTEGER temp;
	INTEGER iCaviEd = -1;
	INTEGER hashIt, hashPr;
	bool bFind = false;
	CaviEdg caviEd;
	int size;

	if (iNod1 > iNod2)
	{
		temp = iNod1;
		iNod1 = iNod2;
		iNod2 = temp;
	}

	hashPr = 0;
	hashIt = m_pCaviEdgeHash[iNod1];
	while (hashIt > 0)
	{
		assert(hashIt < m_vecCaviEdges.size());
		if (m_vecCaviEdges[hashIt].iEnd == iNod2)
		{
			bFind = true;
			break; /* hashIt > 0  */
		}

		hashPr = hashIt;
		hashIt = m_vecCaviEdges[hashIt].hashNxt;
	}

	if (!bFind)
	{/* not find it  */
		if (m_vecCaviEdges.size() == 0)
		{/* initially, we push back a null value  */
			m_vecCaviEdges.push_back(caviEd);
		}

		caviEd.iEnd = iNod2;
		caviEd.hashNxt = 0;

		size = m_vecCaviEdges.size();
		m_vecCaviEdges.push_back(caviEd);

		if (hashPr)
		{
			assert(m_vecCaviEdges[hashPr].hashNxt == 0);
			m_vecCaviEdges[hashPr].hashNxt = size;
		}
		else
		{
			m_pCaviEdgeHash[iNod1] = size;
			m_vecCaviENodeRef.push_back(iNod1);
		}
	}

	return bFind ? 0 : 1;
}

