void DTIso3D::addBaseElem(INTEGER iBaseE)
{
	/* --------------------------------------------------------------
	* 预防重复增加
	* ------------------------------------------------------------- */
	if (isBaseElem(iBaseE))
		return;

	/* --------------------------------------------------------------
	* 标志空腔边界为激活状态
	* ------------------------------------------------------------- */
	flagBaseElem(iBaseE, 1);

	if (!isBaseElemOverset(iBaseE))
	{
		m_vecBaseElems.push_back(iBaseE);
		flagBaseElemOverset(iBaseE, 1);
	}
}

