/* 利用一个新数组来存储新创建的节点  */
INTEGER	DTIso3D::autCreNodes_NewArr(bool bEraseOldMem)
{
	INTEGER i, iEle;
	Elem* pEle;
	MBLNode* pNodes[DIM + 1];
	MYPOINT pnt;
	REAL dp, dt;
	int m, n;
	INTEGER size = m_vecNewCreEles.size();

	if (bEraseOldMem || size > m_nCreateNodes)
	{
		if (m_pCreateNodes != nullptr)
		{
			free(m_pCreateNodes);
			m_pCreateNodes = nullptr;
		}

		if (!(m_pCreateNodes = (MBLNode*)malloc(sizeof(MBLNode) * (size + 1))))
		{
			spdlog::info("Not enough memory.\n");
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;
		}
	}
	memset(m_pCreateNodes, 0, sizeof(MBLNode) * (size + 1));
	m_nCreateNodes = 0;

	/* -----------------------------------------------------------
	* 注意：
	* 1. m_pCreateNodes的索引从1开始
	* 2. m_vecNewCreEles可能存在重复单元
	* ---------------------------------------------------------- */
	for (i = 0; i < size; i++)
	{
		iEle = m_vecNewCreEles[i];
		pEle = &m_pElems[iEle];

		/* m_vecNewCreEles可能存在重复单元  */
		if (isTstEle(pEle))
			continue;
		addTstEle(iEle, pEle);

		if (!isDelEle(pEle) &&

			pEle->form[0] >= INIT_NOD_NUM &&
			pEle->form[1] >= INIT_NOD_NUM &&
			pEle->form[2] >= INIT_NOD_NUM &&
			pEle->form[3] >= INIT_NOD_NUM)
		{
			for (m = 0; m <= DIM; m++)
				pNodes[m] = &m_pNodes[pEle->form[m]];

			for (m = 0; m < DIM; m++)
			{
				pnt[m] = 0.0;
				for (n = 0; n <= DIM; n++)
					pnt[m] += pNodes[n]->pt[m];
				pnt[m] /= DIM + 1;
			}

			//#TODO1 在pure sizing function模式下，需要尺寸值不是插值得到，而是通过对位置进行尺寸计算得到
			dp = 0.0;
			for (n = 0; n <= DIM; n++)
				dp += pNodes[n]->space;
			dp /= DIM + 1;

			for (n = 0; n <= DIM; n++)
			{
				dt = sqrt(squaDist(m_pNodes[pEle->form[n]].pt, pnt));
				if (dt < m_fAlpha * dp && dt < m_fAlpha * pNodes[n]->space)
					break;
			}

			if (n > DIM)
			{
				m_nCreateNodes++;
				m_pCreateNodes[m_nCreateNodes].space = dp;
				for (m = 0; m < DIM; m++)
					m_pCreateNodes[m_nCreateNodes].pt[m] = pnt[m];
				setPrtEle(m_nCreateNodes, iEle);
				setCldNod(iEle, m_nCreateNodes);
			}
			else
				pEle->iReserved = 0;
		}
	}

	clrTstEles();
	m_vecNewCreEles.clear();
	return 1;
}

#ifdef _ROBUST_BW_KERNEL
INTEGER DTIso3D::getPrtEle(INTEGER iNod)
{
	INTEGER iEle = -1;
	assert(iNod >= 1 && iNod <= m_nCreateNodes);/* iNod = 0会引起歧义，不允许  */
	iEle = m_pCreateNodes[iNod].iReserved >> 2;
#ifdef _ONE_LONG_ARRAY
	assert(iEle >= 0 && iEle < m_nElems);
#else
	assert(iEle >= 0 && iEle < m_pElems.getArraySize());
#endif
	return iEle;
}
#else
INTEGER DTIso3D::getPrtEle(INTEGER iNod)
{
	assert(iNod >= 0 && iNod < m_nNodes);
	return getCavSideInd(iNod);
}
#endif

#ifdef _ROBUST_BW_KERNEL
int DTIso3D::setPrtEle(INTEGER iNod, INTEGER iEle)
{
	assert(iNod >= 1 && iNod <= m_nCreateNodes);/* iNod = 0会引起歧义，不允许  */
#ifdef _ONE_LONG_ARRAY
	assert(iEle >= 0 && iEle < m_nElems);
#else
	assert(iEle >= 0 && iEle < m_pElems.getArraySize());
#endif
	m_pCreateNodes[iNod].iReserved &= 0x3;
	m_pCreateNodes[iNod].iReserved |= iEle << 2;
	return 1;
}
#else
int DTIso3D::setPrtEle(INTEGER iNod, INTEGER iEle)
{
	assert(iNod >= 0 && iNod < m_nNodes);
	return setCavSideInd(iNod, iEle);
}
#endif

int DTIso3D::setCldNod(INTEGER iEle, INTEGER iNod)
{
	/* iReserved域的后4+DIM位存储Child Node信息  */
#ifdef _ONE_LONG_ARRAY
	assert(iEle >= 0 && iEle < m_nElems);
#else
	assert(iEle >= 0 && iEle < m_pElems.getArraySize());
#endif
	assert(iNod >= 0);/* 有效的iNod必须大于1，iNod = 0表示没有子节点  */
#if 0
#if DIM == 2
	m_pElems[iEle].iReserved &= 0x3f;
#elif DIM == 3
	m_pElems[iEle].iReserved &= 0x7f;
#else
	assert(false);	/* NOT VALID YET  */
#endif
	m_pElems[iEle].iReserved |= (iNod << (4 + DIM));
#endif
	m_pElems[iEle].iReserved &= 0x3;	/* 将除前2位外后面所有位清0  */
	m_pElems[iEle].iReserved |= (iNod << 2); /* 设置iNod标志  */
	return 1;
}

INTEGER DTIso3D::getCldNod(INTEGER iEle)
{
#ifdef _ONE_LONG_ARRAY
	assert(iEle >= 0 && iEle < m_nElems);
#else
	assert(iEle >= 0 && iEle < m_pElems.getArraySize());
#endif
	INTEGER cpy = m_pElems[iEle].iReserved;
#if 0
	return cpy >> (4 + DIM);
#endif
	return cpy >> 2;
}

