int DTIso3D::addInnerNode(INTEGER iNod)
{
	int i, k, m, l;
	INTEGER ele, iElem, iSrch;
	INTEGER nnew[DIM + 1];
	MYPOINT pnew[DIM + 1];
	MYPOINT cen;
	REAL tv, rad; /*volume & square of radius of ia element */
	INTEGER iEmp; /*empty position for new created element */
	INTEGER m1, m2, i1, i2;
	int nfc = 0, nsc = 0, npc = 0;
	int nCase = -2;
	int if_cav = 0; //if ia cavity face is found: 1 found 0 unfound
	int ss[] = { 1, 2, 0 };
	int ee[] = { 2, 0, 1 };
	int iLast = 0, iCavSid;
	REAL dt, cri;
	REAL dc;
	MYPOINT pnt;
	const int fac_form[4][DIM] =
	{
		{3, 2, 1}, {0, 2, 3}, {3, 1, 0}, {0, 1, 2}
	};
	Elem* pElem, * pSrch;

#ifdef _ERROR_CHK
	int nErrCd = 0;
#endif /*_ERROR_CHK */

	ele = getPrtEle(iNod);
	for (m = 0; m < DIM; m++)
		pnt[m] = m_pNodes[iNod].pt[m];

	/*perform tree search */
	addDeleted(ele);
	addTreeSearch(ele);
	while (!isTreeSearchEmpty())
	{
		iElem = pickTreeSearch();
		pElem = &m_pElems[iElem];
		for (i = 0; i <= DIM; i++)
		{
			iSrch = (pElem->neig)[i];
			if_cav = 1;
			if (iSrch != NULL_NEIG)
			{
				pSrch = &m_pElems[iSrch];
				if_cav = 0;
				if (!isDelEle(pSrch))
				{
					dt = squaDist(pSrch->cen, pnt); /*distance square between two MYPOINTs */
					cri = dt - pSrch->rad;

					if (cri < -EPS_ZERO_SQ)
					{/*incircle criteria is broken */
						addDeleted(iSrch);
						addTreeSearch(iSrch);
					}
					else if (cri > EPS_ZERO_SQ)/*incircle criteria is kept, perform tree search */
					{
						if_cav = 1;
					}/* else if (cri > EPS_ZERO_SQ)  */
					else
					{/* four MYPOINTs in the same circle  */
						nCase = 0;
						goto RECOVERED;
					}
				}/*if (!isTested(pSrch) && isValid(pSrch)) */
			}/* if (iSrch != NULL_NEIG)  */
			if (if_cav == 1)/* a cavity face is found  */
			{
				/*
				* we always assume that:
				* in an element, the face faced by MYPOINT form[i] is neighbored
				* by element neig[i]
				 */
				for (l = 0; l < DIM; l++)
				{
					nnew[l] = (m_pElems[iElem].form)[fac_form[i][l]];
					for (m = 0; m < DIM; m++)
						pnew[l][m] = (m_pNodes[nnew[l]].pt)[m];
				}

				nnew[DIM] = iNod; /*add ia node */
				for (m = 0; m < DIM; m++)
					pnew[DIM][m] = pnt[m];
				calcElePar(pnew, &tv, &cen, &rad);

				/* error check  */
				if (tv <= 0.0)
				{
#ifdef _VERBOSE
					spdlog::info("{} negative or near zero volume!!\n", iNod);
#endif
					nCase = -2;
					goto RECOVERED;
				}

				nfc = nfc + 1;

				iEmp = getNewEleLoc();
				crtEle(iEmp, nnew, cen, rad); /*create ia new element & return its location */
				((m_pElems)[iEmp].neig)[DIM] = iSrch;

				/*check the cavity MYPOINT */
				for (k = 0; k < DIM; k++)
				{
					i1 = ((m_pElems)[iEmp].form)[k];
					int flag = getNodeFlag(i1);
					if (flag == 0)
					{
						/*
						* if it is too close to the cavity node,
						* the inserted node is rejected
						 */
						dc = sqrt(squaDist(m_pNodes[i1].pt, pnt));
						if (dc < m_fAlpha * m_pNodes[i1].space &&
							dc < m_fAlpha * m_pNodes[iNod].space)
						{
							nCase = -1;
#ifdef _ERROR_CHK
							g_nRejectTotal++;
#endif
							goto RECOVERED;
						}

						npc = npc + 1;
						addCavNode(i1);
					}
				}

				/*
				* check two nodes of the created element. if they are taken by ia new created element,
				* then update the neighboring information correspondingly
				 */
				for (k = 0; k < DIM; k++)
				{
					m1 = nnew[ss[k]];
					m2 = nnew[ee[k]];
					i1 = m1 > m2 ? m2 : m1;
					i2 = m1 > m2 ? m1 : m2;
					iCavSid = getCavSide(i1, i2, &iLast);
					if (iCavSid > 0)
					{
						assert(iCavSid < m_vecCavSides.size());
						CavSide* pcs = &m_vecCavSides[iCavSid];
						((m_pElems)[iEmp].neig)[k] = pcs->iEle;
						((m_pElems)[pcs->iEle].neig)[pcs->iNei] = iEmp;
					}
					else
					{
						addCavSide(i1, i2, iEmp, k, iLast);
						nsc = nsc + 1;
					}
				}
			}
		}/*for (i = 0; i < DIM; i++) */
	}/*while (!isTreeSearchEmpty()) */

	if (nfc != (DIM - 1) * npc - 4 * (DIM - 2))
	{
		spdlog::info("{} the number of faces & the number of nodes is imbalant!\n", iNod);
		nCase = -2;
		goto RECOVERED;
	}

	g_nInnInstPoint++;
	g_nInnTotalCaviElem += m_vecDelEles.size();

	nCase = 1;

	updateNeigInfo();

	/*
	* update the empty locations by moving
	* all deleted elements to the array of empty locations
	 */
	updateEmpLocs();

	/*
	* While Add Inner Node, we should flag DISCARDED to those
	* nodes whose parent elements have been deleted
	 */
	updateDiscNods();

	/*
	* 将所有新创建的单元加入到m_vecNewCreEles中
	 */
	addNewCreEles();

	goto FINISHED;

RECOVERED:
	//clear all elements in the stack of tree searching
	clrTreeSearEles();

	//recover all deleted elements
	recoverDelEles();

	//recover all empty locations
	recoverEmpLocs();

	//recover all new elements
	recoverNewEles();

FINISHED:
	/* clear the array of deleted elements  */
	m_vecDelEles.clear();

	/* clear the array of new elements  */
	clrNewEles();

	/* clear the array of tested elements  */
	/*	clrTstEles();  */

	/* clear the array of cavity sides  */
	m_vecCavSides.clear();

	/* clear the array of cavity nodes  */
	clrNodeReserved();

#ifdef _ERROR_CHK

	/*	nErrCd = checkGlobalData();
	if (nErrCd != 0)
	{
	printError(nErrCd);
	} */
#endif

	/* clear iReserved domain (back 30 bits only) */
	if (nCase == 1)
		m_pNodes[iNod].iReserved = 0;
	return nCase;
}

int DTIso3D::updateDiscNods()
{
	int i, size, nCnt = 0;
	INTEGER iEle, iNod;
	size = m_vecDelEles.size();
	for (i = 0; i < size; i++)
	{
		iEle = m_vecDelEles[i];
		iNod = getCldNod(iEle);
		if (iNod > 0)
		{/* a child node appending to the element  */
#ifdef _ERROR_CHK
			assert(!isDiscard(iNod));
			if (!isDiscard(iNod))
			{
				g_nDiscardTotal++;
			}
#endif /* _ERROR_CHK  */
			setDiscard(iNod, true);
			/*clear the flag */
			setCldNod(iEle, 0);
			nCnt++;
		}
	}

	return nCnt;
}

int DTIso3D::bakEraseNod(INTEGER iNodS, INTEGER * iNodE)
{
	INTEGER iNod, iEle;
	for (iNod = *iNodE; iNod >= iNodS; iNod--)
	{
#if 0
		/*		iEle = getPrtEle(iNod);
		if (!isDelEle(iEle))
		break; */
		if (isDiscard(iNod))
		{
			iEle = getPrtEle(iNod);
			assert(m_pElems[iEle].iReserved == 0);
		}
		else
			break;
#endif
		if (!isDiscard(iNod))
			break;
	}

	*iNodE = iNod;

	return 1;
}

int DTIso3D::distNode(INTEGER iNod)
{
	int m;
	for (m = 0; m < DIM; m++)
	{
		(m_pNodes[iNod].pt)[m] = (m_pNodes[iNod].pt)[m] * (1.0 + DISTURB_RATIO * m_pNodes[iNod].space);
	}

	return 1;
}

INTEGER DTIso3D::findSwapNode(INTEGER iNod, INTEGER * iNodE)
{
	bakEraseNod(iNod, iNodE);

	return *iNodE;
}

int DTIso3D::swapNode(INTEGER iNod, INTEGER iSwap)
{
	INTEGER it;
	REAL ft;
	int m;

	ft = m_pNodes[iNod].space;
	m_pNodes[iNod].space = m_pNodes[iSwap].space;
	m_pNodes[iSwap].space = ft;

	it = m_pNodes[iNod].iReserved;
	m_pNodes[iNod].iReserved = m_pNodes[iSwap].iReserved;
	m_pNodes[iSwap].iReserved = it;

	for (m = 0; m < DIM; m++)
	{
		ft = (m_pNodes[iNod].pt)[m];
		(m_pNodes[iNod].pt)[m] = (m_pNodes[iSwap].pt)[m];
		(m_pNodes[iSwap].pt)[m] = ft;
	}

	return 1;
}

REAL DTIso3D::spacFrmPnt(PntSource * src, MYPOINT pt)
{
	REAL diff, ae;
	const REAL BIG = 50;
	REAL CLG2 = log(2.0);
	REAL dist = sqrt(squaDist(src->cen, pt));
	if (dist <= src->in_rad)
	{
		return src->space;
	}
	else
	{
		dist = dist - src->in_rad;
		diff = src->ou_rad - src->in_rad;
		if (diff <= 0.0)
		{
			spdlog::info("Error point source \n");
			return 1.0e10;
		}
		else
		{
			diff = CLG2 / diff;
			ae = dist * diff < BIG ? dist * diff : BIG;
			return src->space * exp(ae);
		}
	}
}

REAL DTIso3D::spacFrmLne(PntSource * src1, PntSource * src2, MYPOINT pt)
{
	REAL sca = 0.0;
	REAL w1, w2;
	/*	REAL tolg = 1e-5; */
	VECTOR v12;
	PntSource src3;
	int i;
	REAL dist = sqrt(squaDist(src1->cen, src2->cen));
	if (dist < EPS_ZERO)
	{
		spdlog::info("Error distance.\n");
		return 1.0e10;
	}

	//将点投影到线段所在直线上，若超出线段所在范围，则采用靠近一段的端点点源，否则采用端点插值形成的点源
	for (i = 0; i < DIM; i++)
	{
		v12[i] = (src2->cen[i] - src1->cen[i]) / dist;
	}
	for (i = 0; i < DIM; i++)
	{
		sca += (pt[i] - src1->cen[i]) * v12[i];
	}

	if (sca <= 0.0)
	{
		return spacFrmPnt(src1, pt);
	}
	else if (sca >= dist)
	{
		return spacFrmPnt(src2, pt);
	}
	else
	{
		w2 = sca / dist;
		w1 = 1.0 - w2;
		for (i = 0; i < DIM; i++)
		{
			src3.cen[i] = w1 * src1->cen[i] + w2 * src2->cen[i];
		}
		src3.in_rad = w1 * src1->in_rad + w2 * src2->in_rad;
		src3.ou_rad = w1 * src1->ou_rad + w2 * src2->ou_rad;
		src3.space = w1 * src1->space + w2 * src2->space;
		return spacFrmPnt(&src3, pt);
	}
}

REAL DTIso3D::spacFrmTri(PntSource * src1, PntSource * src2, PntSource * src3, MYPOINT pt)
{
	REAL sca = 0;
	REAL w1, w2, w3, sh1 = 0.0, sh3 = 0.0, h1 = 0.0, h3 = 0.0;
	/*	REAL tolg = 1e-5; */
	PntSource src4;
	VECTOR v12, v23, v31;
	VECTOR nt, n12, n23;
	VECTOR v2p;
	int i;
	REAL dist;

	//将点投影到三角所在平面，若超出三角所在范围，则采用靠近一段的端点点源，否则采用端点插值形成的点源
	for (i = 0; i < DIM; i++)
	{
		v12[i] = src2->cen[i] - src1->cen[i];
	}
	dist = squaDist(src1->cen, src2->cen);
	if (dist < EPS_ZERO_SQ)
	{
		spdlog::info("Error distance\n");
		return 1.0e10;
	}

	for (i = 0; i < DIM; i++)
	{
		v23[i] = src3->cen[i] - src2->cen[i];
	}
	dist = squaDist(src3->cen, src2->cen);
	if (dist < EPS_ZERO_SQ)
	{
		spdlog::info("Error distance\n");
		return 1.0e10;
	}

	for (i = 0; i < DIM; i++)
	{
		v31[i] = src1->cen[i] - src3->cen[i];
	}
	dist = squaDist(src1->cen, src3->cen);
	if (dist < EPS_ZERO_SQ)
	{
		spdlog::info("Error distance\n");
		return 1.0e10;
	}

	/*normal to the triangle nt = v12^v23 */
	crossVect(v12, v23, &nt);

	/* normal to side 1-2 n12=nt^v12  */
	crossVect(nt, v12, &n12);

	/*normal to side 2-3 n23 = nt^v23  */
	crossVect(nt, v23, &n23);

	for (i = 0; i < DIM; i++)
	{
		v2p[i] = pt[i] - src2->cen[i];
	}

	/* compute area weights, using the point projected to the triangle  */
	for (i = 0; i < DIM; i++)
	{
		h1 += v2p[i] * n23[i];
		sh1 += -v12[i] * n23[i];
		h3 += v2p[i] * n12[i];
		sh3 += v23[i] * n12[i];
	}
	w1 = h1 / sh1;
	w3 = h3 / sh3;
	w2 = 1.0 - w1 - w3;

	if (w1 <= 0.0)
	{
		return spacFrmLne(src2, src3, pt);
	}
	else if (w2 <= 0.0)
	{
		return spacFrmLne(src1, src3, pt);
	}
	else if (w3 <= 0.0)
	{
		return spacFrmLne(src1, src2, pt);
	}
	else
	{
		for (i = 0; i < DIM; i++)
		{
			src4.cen[i] = w1 * src1->cen[i] + w2 * src2->cen[i] + w3 * src3->cen[i];
		}
		src4.in_rad = w1 * src1->in_rad + w2 * src2->in_rad + w3 * src3->in_rad;
		src4.ou_rad = w1 * src1->ou_rad + w2 * src2->ou_rad + w3 * src3->ou_rad;
		src4.space = w1 * src1->space + w2 * src2->space + w3 * src3->space;
		return spacFrmPnt(&src4, pt);
	}
}

REAL DTIso3D::fromSrc(MYPOINT pnt)
{
#ifdef USE_SIZING_FUNC
#if DIM != 3
#error
#endif
	REAL den = 1.e10, spac;

	if (hasSizingFunc()) {
		spac = sizingFunc(pnt[0], pnt[1], pnt[2]);
		//static int count = 0;
		//if(count++%500==0)
		//cout << spac << " ";
		//
		//MYPOINT pt;
		//pt[0] = 207.54436;
		//pt[1] = -206.81951;
		//pt[2]=3.3799215;
		//wToN(pt, &pt);
		//cout<< sizingFunc(pt[0],pt[1],pt[2]);
		//exit(0);
		return spac > 0 ? spac : den;
	}
	else {
		int j;
		REAL den = 1.e10, spac;

		/* point source control  */
		for (j = 0; j < m_Source.nPntS; j++)
		{
			spac = spacFrmPnt(&m_Source.pPntS[j], pnt);
			if (den > spac)
				den = spac;
		}
		/* line source control  */
		for (j = 0; j < m_Source.nLinS; j++)
		{
			spac = spacFrmLne(&m_Source.pLinS[j].src[0],
				&m_Source.pLinS[j].src[1],
				pnt);
			if (den > spac)
				den = spac;
		}
		/* triangle source control  */
		for (j = 0; j < m_Source.nTriS; j++)
		{
			spac = spacFrmTri(&m_Source.pTriS[j].src[0],
				&m_Source.pTriS[j].src[1],
				&m_Source.pTriS[j].src[2],
				pnt);
			if (den > spac)
				den = spac;
		}
		return den;
	}
#else
	if (GetSizingFuntion()) {
		//wToN(wp, &(m_pNodes[i].pt));
		std::array<double, 3> t;
		for (int i = 0; i < DIM; i++)
			t[i] = (pnt[i] - m_cenN[i]) / m_scale + m_cenW[i];
		double size = GetSizingFuntion()(t);
		wToN(size, &size);
		den = min(den, size);
	}

	return den;
#endif // VTK_SIZING_FUNCTION
}

int DTIso3D::assiNode(INTEGER iNod, INTEGER iAssi)
{
	int m;

	m_pNodes[iNod].space = m_pNodes[iAssi].space;
	m_pNodes[iNod].iReserved = m_pNodes[iAssi].iReserved;
	for (m = 0; m < DIM; m++)
		(m_pNodes[iNod].pt)[m] = (m_pNodes[iAssi].pt)[m];

	return 1;
}

INTEGER DTIso3D::swapNodSpacs(INTEGER iNod, INTEGER iDegS, INTEGER iDegE)
{
	INTEGER iSwap = 0, iDeg;
	INTEGER iEle;

	for (iDeg = iDegE; iDeg > iDegS; iDeg--)
	{
		iEle = getPrtEle(iDeg);
		if (!isDelEle(&m_pElems[iEle]))
		{
			if (!iNod != iDeg)
				assiNode(iNod, iDeg);

			iNod++;
			iSwap++;
		}
	}

	return iSwap;
}
/*
* remove deleted elements & redundant nodes
 */
int DTIso3D::rmvNodsAndEles()
{
	INTEGER i, j = 0, k, iNeig, i1, i2, i3, iFac;
	INTEGER iRmvNodCnt = 0, iRmvEleCnt = 0;
	DesFacet* pDF = nullptr;
	int m, mm;
	Elem* pElem, * pElemK, * pElemN;
	MBLNode* pNode, * pNodeK;

#ifdef _ONE_LONG_ARRAY
	INTEGER elemSize = m_nElems, nodeSize = m_nNodes;
#else
	INTEGER elemSize = m_pElems.getArraySize(), nodeSize = m_pNodes.getArraySize();
#endif
	INTEGER faceHd, faceIt, faceTl;

	/* 记录节点和单元使用的峰值  */
	m_nPeakElems = elemSize;
	m_nPeakNodes = nodeSize;

	/* ****************************************************************
	* 删除多余节点
	* delete redundant nodes
	* ************************************************************** */
	/*
	* 注意，内部插入的点中也可能需要被删除
	* take care to delete some points innerly inserted
	 */
	for (i = 0; i < nodeSize; i++)
	{
		m_pNodes[i].iReserved = 0;
	}

	for (i = 0; i < elemSize; i++)
	{
		pElem = &m_pElems[i];
		if (!isDelEle(pElem))
		{
			for (m = 0; m <= DIM; m++)
			{
				m_pNodes[pElem->form[m]].iReserved++;
			}
		}
	}

	for (i = 0, j = 0; i < nodeSize; i++)
	{
		pNode = &m_pNodes[i];
		if (pNode->iReserved == 0)
		{
			j++;
			pNode->iReserved = -1;
		}
		else
		{
			k = i - j; /* new position  */
			if (j > 0)
			{/* move node i to k  */
				pNodeK = &m_pNodes[k];
				pNodeK->pt[0] = pNode->pt[0];
				pNodeK->pt[1] = pNode->pt[1];
				pNodeK->pt[2] = pNode->pt[2];
				pNodeK->space = pNode->space;
				pNodeK->iReserved2 = pNode->iReserved2;
			}
			pNode->iReserved = k; /* position after remove  */
		}
	}
	iRmvNodCnt = j;

#if 0
	for (i = 0, j = 0; i < nodeSize; i++)
	{
		pNode = &m_pNodes[i];
		if (m_pNodes[i].iReserved >= 0)
		{
			for (m = 0; m < DIM; m++)
				(m_pNodes[j].pt)[m] = (m_pNodes[i].pt)[m];
			m_pNodes[j].space = m_pNodes[i].space;
			j++;
		}
	}
#endif

#ifdef _ONE_LONG_ARRAY
	m_nNodes -= iRmvNodCnt;
#else
	m_pNodes.setArraySize(m_pNodes.getArraySize() - iRmvNodCnt);
#endif
	m_bWithOutBoxNodes = false;

	/* ****************************************************************
	* 删除多余单元
	* delete redundant elements
	* ************************************************************** */
	for (i = 0, j = 0; i < elemSize; i++)
	{
		pElem = &m_pElems[i];
		if (isDelEle(pElem))
		{
			j++;
			pElem->iReserved = NULL_ELEM;
		}
		else
		{
			k = i - j;
#if 1
			if (j > 0)
			{
				pElemK = &m_pElems[k];
				//disabledDeleted(pElemK);//保证它未被删除
				pElemK->iReserved2 = pElem->iReserved2;
				pElemK->iReserved3 = pElem->iReserved3;
				pElemK->rad = pElem->rad;
				pElemK->cen[0] = pElem->cen[0];
				pElemK->cen[1] = pElem->cen[1];
				pElemK->cen[2] = pElem->cen[2];

				for (m = 0; m <= DIM; m++)
				{
					iNeig = (pElem->neig)[m];
					if (iNeig != NULL_NEIG)
					{/* 邻居已经就位  */
						if (iNeig < i)
						{
							pElemN = &m_pElems[iNeig];
							(pElemK->neig)[m] = pElemN->iReserved;
							pElemN = &m_pElems[pElemN->iReserved];
							for (mm = 0; mm <= DIM; mm++)
								if (pElemN->neig[mm] == i)
								{/* 等于i  */
									pElemN->neig[mm] = k;
									break;
								}
							assert(mm <= DIM);
						}
						else
							(pElemK->neig)[m] = iNeig;
					}
					else
						(pElemK->neig)[m] = NULL_NEIG;
				}
			}
			else
				pElemK = pElem;

			for (m = 0; m <= DIM; m++)
				(pElemK->form)[m] = m_pNodes[pElem->form[m]].iReserved; /* 形成节点  */
#endif

			pElem->iReserved = k; /* position after remove  */
		}
	}
	iRmvEleCnt = j;

#if 0
	for (i = 0, k = 0; i < elemSize; i++)
	{
		pElem = &m_pElems[i];
		if (!isDelEle(pElem))
		{/*remove the deleted element to the position of m_pElems[i].iReserved */
			pElemK = &m_pElems[k];
			//			setDeleted(j, 0);//保证它未被删除
			pElemK->iReserved2 = pElem->iReserved2; //保证它未被删除
			pElemK->rad = pElem->rad;
			pElemK->cen[0] = pElem->cen[0];
			pElemK->cen[1] = pElem->cen[1];
			pElemK->cen[2] = pElem->cen[2];

			for (m = 0; m <= DIM; m++)
			{
				(pElemK->form)[m] = m_pNodes[pElem->form[m]].iReserved;
				iNeig = (m_pElems[i].neig)[m];
				if (iNeig != NULL_NEIG)
				{
					(pElemK->neig)[m] = m_pElems[iNeig].iReserved;
				}
				else
				{
					(pElemK->neig)[m] = NULL_NEIG;
				}
			}

			k++;
		}
	}
#endif

#ifdef _ONE_LONG_ARRAY
	m_nElems -= iRmvEleCnt;
	elemSize = m_nElems;
#else
	m_pElems.setArraySize(m_pElems.getArraySize() - iRmvEleCnt);
	elemSize = m_pElems.getArraySize();
#endif

	/* 更新面片的节点索引  */
	for (i = 0; i < m_nSurTris; i++)
	{
		m_pSurTris[i].form[0] = m_pNodes[m_pSurTris[i].form[0]].iReserved;
		m_pSurTris[i].form[1] = m_pNodes[m_pSurTris[i].form[1]].iReserved;
		m_pSurTris[i].form[2] = m_pNodes[m_pSurTris[i].form[2]].iReserved;
	}

	/* 更新边哈希表的节点索引  */
	for (i = 0; i < m_nSurEdgeHash_MaxIdx; i++)
	{
		j = m_pNodes[i].iReserved;
		/* 如果j是一个有效的值，表明该节点为有效  */
		if (j >= 0)
		{
			if (j >= m_nSurEdgeHash_MaxIdx)
			{
				spdlog::info("Should not be here. The node idx {} is bigger than its maximal limit {}.\n", j + 1, m_nSurEdgeHash_MaxIdx);
				throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;
			}
			m_pSurEdgHash[j] = m_pSurEdgHash[i];
		}
	}
	for (i = 1; i <= m_nSurEdgs; i++)
	{
		j = m_pSurEdgs[i].iStart;
		j = m_pNodes[j].iReserved;
		if (j >= 0)
		{
			m_pSurEdgs[i].iStart = j;
			j = m_pSurEdgs[i].iEnd;
			j = m_pNodes[j].iReserved;
		}

		if (j >= 0)
			m_pSurEdgs[i].iEnd = j;
		else
		{
			spdlog::info("Error! There may exist hanging face outside the block!");
			//spdlog::info("Should not be here. An ending node ({}) of a boundary edge is invalid.\n", j + 1);
			//spdlog::info("The edge is shared by the faces as below:");
			//faceIt = faceHd = m_pSurEdgs[i].face;
			//i1 = m_pSurEdgs[i].iStart;
			//i2 = m_pSurEdgs[i].iEnd;
			//assert(faceHd >= 0);
			//do
			//{
			//	spdlog::info(" {}", faceIt + 1);
			//	for (k = 0; k < 3; k++)
			//		if (m_pSurTris[faceIt].form[k] != i1 &&
			//			m_pSurTris[faceIt].form[k] != i2)
			//			break;
			//	assert(k < 3);
			//	faceTl = faceIt;
			//	faceIt = m_pSurTris[faceIt].neig[k];
			//} while (faceIt != faceHd);
			//spdlog::info("\n");
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));
		}
	}

	//#ifndef _CONSTRAINED_RECOVERY
		/* 更新子面片的节点索引  */
	for (i = 1; i <= m_nDesFacets; i++)
	{
		pDF = &m_pDesFacets[i];
		iFac = pDF->iFac;
		for (j = 0; j < pDF->nSubFts; j++)
		{
			i1 = pDF->subFts[j][0];
			i2 = pDF->subFts[j][1];
			i3 = pDF->subFts[j][2];
			//			pDF->subFts[j][0] = m_pNodes[i1].iReserved;
			//			pDF->subFts[j][1] = m_pNodes[i2].iReserved;
						//                      pDF->subFts[j][2] = m_pNodes[i3].iReserved;
			if (i1 > 0)
				pDF->subFts[j][0] = m_pNodes[i1].iReserved;
			else
				pDF->subFts[j][0] = -1;
			if (i2 > 0)
				pDF->subFts[j][1] = m_pNodes[i2].iReserved;
			else
				pDF->subFts[j][1] = -1;
			if (i3 > 0)
				pDF->subFts[j][2] = m_pNodes[i3].iReserved;
			else
				pDF->subFts[j][2] = -1;
		}
	}
	//#endif

#if 0
	/* all splitted nodes in the outer of the domain is removed  */
	for (i = 1; i <= m_nDesEdges; i++)
		m_nNodes -= m_pDesEdges[i].nNodes - 2;
	for (i = 1; i <= m_nDesFacets; i++)
		m_nNodes -= m_pDesFacets[i].nNodes;
#endif

	return 1;
}

/*
* fill the parent domains of all surface
 */
int DTIso3D::fillParents(bool bConformal)
{
	INTEGER i, j;
	INTEGER i1, i2, i3, iFac;
	SurTri* pST = nullptr;
	DesFacet* pDF = nullptr;
	bool* visited = nullptr;
#ifdef _ONE_LONG_ARRAY
	INTEGER elemSize = m_nElems;
#else
	INTEGER elemSize = m_pElems.getArraySize();
#endif

	abstNodFirEle();
	for (i = 0; i < elemSize; i++)
	{
		m_pElems[i].iReserved = 0;
	}

	if (!bConformal)
	{
		for (i = 0; i < m_nSurTris; i++)
		{
			pST = &m_pSurTris[i];
			i1 = pST->form[0];
			i2 = pST->form[1];
			i3 = pST->form[2];
			pST->parent = findParent(i1, i2, i3);
			if (pST->parent < 0)
			{
				/* for some nodes there may be not only one manifold attached to it, then
				search the parent locally may fail. So we try to search the parent in
				a brute-force manner  */
				pST->parent = findParent_BruteForce(i1, i2, i3);
				if (pST->parent < 0)
					spdlog::info("Error! invalid parent element {}\n", i);
				else
					spdlog::info("More than one manifold attached to the nodes of facets ({}).\n", i);
			}
		}
	}
	else
	{
		/* 保形边界恢复，一个面片可能被分成几个小面片，我们先输出分解得到的面片  */
		visited = new bool[m_nSurTris];
		memset(visited, 0, sizeof(bool) * m_nSurTris);
		for (i = 1; i <= m_nDesFacets; i++)
		{
			pDF = &m_pDesFacets[i];
			iFac = pDF->iFac;
			for (j = 0; j < pDF->nSubFts; j++)
			{
				i1 = pDF->subFts[j][0];
				i2 = pDF->subFts[j][1];
				i3 = pDF->subFts[j][2];
				assert(i1 >= 0 && i2 >= 0 && i3 >= 0);
#ifdef _ONE_LONG_ARRAY
				assert(i1 < m_nNodes && i2 < m_nNodes && i3 < m_nNodes);
#else
				assert(i1 < m_pNodes.getArraySize() && i2 < m_pNodes.getArraySize() && i3 < m_pNodes.getArraySize());
#endif
				pDF->subEls[j][0] = findParent(i1, i2, i3);/* 将其填充到subFts的subEls[0]中  */
				if (pDF->subEls[j][0] < 0)
				{
					pDF->subEls[j][0] = findParent_BruteForce(i1, i2, i3);
					if (pDF->subEls[j][0] < 0)
						spdlog::info("Error! unvalid parent element of the subface of an original face {}\n", iFac);
					else
						spdlog::info("More than one manifold attached to a face node ({}).\n", i1);
				}
			}
			visited[iFac] = true;
		}
		for (i = 0; i < m_nSurTris; i++)
		{
			if (!visited[i])
			{
				pST = &m_pSurTris[i];
				i1 = pST->form[0];
				i2 = pST->form[1];
				i3 = pST->form[2];
				pST->parent = findParent(i1, i2, i3);
				if (pST->parent < 0)
				{
					/* for some nodes there may be not only one manifold attached to it, then
					search the parent locally may fail. So we try to search the parent in
					a brute-force manner  */
					pST->parent = findParent_BruteForce(i1, i2, i3);
					if (pST->parent < 0)
						spdlog::info("Error! unvalid parent element {}\n", i);
					else
						spdlog::info("More than one manifold attached to the nodes of facets ({}).\n", i);
				}
			}
		}
	}

	if (visited)
		delete[] visited;

	return 1;
}

int DTIso3D::evalSphereSize()
{
	INTEGER i;
	Sphere sph;
	int nSph = 0;

	abstNodFirEle();

	sphere_size_eval = 0;
	for (i = 0; i < m_nSurNodes; i++)
	{
		findSphere(i, sph, &nSph);
		sphere_size_eval += nSph;
	}
	sphere_size_eval /= m_nSurNodes;

	return 1;
}

INTEGER DTIso3D::findParent(INTEGER i1, INTEGER i2, INTEGER i3)
{
	INTEGER i, j, m;
	Sphere sph;
	int nSph;
	INTEGER iEle = -1;
	Elem* pEle;
	int simCnt = 0;
	INTEGER ii[3] = { i1, i2, i3 };

#ifdef _ERROR_CHK
	int mm;
#endif /* _ERROR_CHK  */

	//	assert(iFac >= 0 && iFac < m_nSurTris);

	for (j = 0; j < DIM; j++)
	{
		findSphere(ii[j], sph, &nSph);
		for (i = 0; i < nSph; i++)
		{
			iEle = sph[i];
			pEle = &m_pElems[iEle];

			simCnt = 0;
			for (m = 0; m <= DIM; m++)
				if (pEle->form[m] == ii[(j + 1) % DIM] || pEle->form[m] == ii[(j + 2) % DIM])
					simCnt++;

			if (simCnt == 2)
				return iEle;
		}
	}

	return -1;
}

INTEGER DTIso3D::findParent_BruteForce(INTEGER i1, INTEGER i2, INTEGER i3)
{
	INTEGER i;
	int simCnt = 0, m;
	Elem* pElem;

#ifdef _ONE_LONG_ARRAY
	INTEGER elemSize = m_nElems;
#else
	INTEGER elemSize = m_pElems.getArraySize();
#endif

	for (i = 0; i < elemSize; i++)
	{
		pElem = &m_pElems[i];
		if (isDelEle(pElem))
			continue;

		simCnt = 0;
		for (m = 0; m < 4; m++)
		{
			if (pElem->form[m] == i1 ||
				pElem->form[m] == i2 ||
				pElem->form[m] == i3)
			{
				simCnt++;
			}
		}
		if (simCnt == 3)
			return i;
	}

	return -1;
}

/*
* 打印约束边界恢复信息
 */
int DTIso3D::printConformalRecvInfo()
{
	INTEGER i;
	INTEGER iEANE, iEANF, iDesFWthNds, iTotal;
	INTEGER nAlloc;
	MBLNode* pNewNodes = nullptr;
	Elem* pNewElems = nullptr;

	iEANE = iEANF = iTotal = 0;

	for (i = 1; i <= m_nDesEdges; i++)
		iEANE += m_pDesEdges[i].nNodes - 2;

	for (i = 1, iDesFWthNds = 0; i <= m_nDesFacets; i++)
	{
		if (m_pDesFacets[i].nNodes > 0)
			iDesFWthNds++;
		iEANF += m_pDesFacets[i].nNodes;
	}

	iTotal = iEANE + iEANF + m_vecSteinerPnt.size();
	/* output basic info. of destoryed boundaries  */
	printf("\nPrepare to remove or reposition Steiner points, please wait...\n");
	printf("DESTROYED EDGES %d\tDESTROYED FACETS %d(%d of interiorly destroyed)\n",
		m_nDesEdges, m_nDesFacets, iDesFWthNds);
	printf("Extra-Added Nodes in \nEDGE %d\tFACET %d\tOTHER %d\tTOTAL %d\n",
		iEANE, iEANF, m_vecSteinerPnt.size(), iTotal);

	return 1;
}

/* ***************************************************
* 为一致边界恢复算法定义的函数
* functions for constrained boundary recovery
* ************************************************* */
/*
* 为完全恢复被破坏边界作数据准备
* prepare to recover destroyed boundaries (edges/facets)
 */
int DTIso3D::prepareRecvDesBnds()
{
	INTEGER i;
	INTEGER iEANE, iEANF, iDesFWthNds, iTotal;
	INTEGER nAlloc;
	MBLNode* pNewNodes = nullptr;
	Elem* pNewElems = nullptr;

	iEANE = iEANF = iTotal = 0;

	for (i = 1; i <= m_nDesEdges; i++)
		iEANE += m_pDesEdges[i].nNodes - 2;

	for (i = 1, iDesFWthNds = 0; i <= m_nDesFacets; i++)
	{
		if (m_pDesFacets[i].nNodes > 0)
			iDesFWthNds++;
		iEANF += m_pDesFacets[i].nNodes;
	}

	iTotal = iEANE + iEANF + m_vecSteinerPnt.size();
#if 0
	/* output basic info. of destoryed boundaries  */
	printf("\nPrepare to remove or reposition Steiner points, please wait...\n");
	printf("DESTROYED EDGES %d\tDESTROYED FACETS %d(%d of interiorly destroyed)\n",
		m_nDesEdges, m_nDesFacets, iDesFWthNds);
	printf("Extra-Added Nodes in \nEDGE %d\tFACET %d\tOTHER %d\tTOTAL %d\n",
		iEANE, iEANF, m_vecSteinerPnt.size(), iTotal);
#endif

#ifdef _ONE_LONG_ARRAY
	/* check memory for nodes  */
	if (m_nNodes + iTotal > m_nAllocNodes)
	{
		//	spdlog::info("try to reallocate memory for nodes\n");
		nAlloc = m_nAllocNodes;
		do
		{
			nAlloc += (INTEGER)(NUM_ADD_RATIO * nAlloc);
		} while (nAlloc < m_nNodes + iTotal);

		pNewNodes = (Node*)realloc(m_pNodes, sizeof(Node) * nAlloc);
		if (!pNewNodes)
		{
			spdlog::info("cannot reallocate memory for nodes:\n");
			spdlog::info("Size={}.\n", nAlloc);
			spdlog::info("Memory=%.1fMB\n", sizeof(Node) * nAlloc / (1024.0 * 1024.0));
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;

			return -1;
		}
		//		printf("successfully reallocate memory for nodes, new size is %d\n", nAlloc);

		m_pNodes = pNewNodes;
		memset(&m_pNodes[m_nNodes], 0, sizeof(Node) * (nAlloc - m_nNodes));
		m_nAllocNodes = nAlloc;
	}

	/* check memory for elements. Need improvment later  */
	if (m_nElems + 10 * iTotal >= m_nAllocElems)
	{
		//	spdlog::info("try to reallocate memory for elements\n");
		nAlloc = m_nAllocElems;
		do
		{
			nAlloc += (INTEGER)(NUM_ADD_RATIO * nAlloc);
		} while (nAlloc <= m_nElems + 10 * iTotal);

		pNewElems = (Elem*)realloc(m_pElems, sizeof(Elem) * nAlloc);
		if (!pNewElems)
		{
			spdlog::info("cannot reallocate memory for elements:\n");
			spdlog::info("Size={}.\n", nAlloc);
			spdlog::info("Memory=%.1fMB\n", sizeof(Elem) * nAlloc / (1024.0 * 1024.0));
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;

			return -1;
		}
		//		printf("successfully reallocate memory for elements, new size is %d\n", nAlloc);

		m_pElems = pNewElems;
		memset(&m_pElems[m_nElems], 0, sizeof(Elem) * (nAlloc - m_nElems));
		m_nAllocElems = nAlloc;
	}
#else
	/* check memory for nodes  */
	if (m_pNodes.getArraySize() + iTotal > m_pNodes.getArrayCapacity())
	{
		//	spdlog::info("try to reallocate memory for nodes\n");
		nAlloc = m_pNodes.getArrayCapacity();
		do
		{
			nAlloc += (INTEGER)(NUM_ADD_RATIO * nAlloc);
		} while (nAlloc < m_pNodes.getArraySize() + iTotal);

		m_pNodes.allocMemory(nAlloc);
	}
	/* check memory for elements. Need improvment later  */
	if (m_pElems.getArraySize() + 10 * iTotal >= m_pElems.getArrayCapacity())
	{
		//	spdlog::info("try to reallocate memory for elements\n");
		nAlloc = m_pElems.getArrayCapacity();
		do
		{
			nAlloc += (INTEGER)(NUM_ADD_RATIO * nAlloc);
		} while (nAlloc <= m_pElems.getArraySize() + 10 * iTotal);

		m_pElems.allocMemory(nAlloc);
	}
#endif

	return 1;
}

/* 恢复所有被破坏边＆面上的点　recovery all extra-added node in the destroyed edges & facets  */
int DTIso3D::recvDesEdges()
{
	DesEdge* pDE;
	INTEGER i;
	int j, k;
	INTEGER currNod, prevNod, nextNod;
	int nSP = 0, nTtlSP = 0, nRmvSP = 0, nRpsSP = 0;
	INTEGER nFullRecv = 0, nPartRecv = 0;

#ifdef _ERROR_CHK
	int nErrCd;
#endif /* _ERROR_CHK  */

	printf("\nRecover destroyed edges, please wait...(Total:%d)\n", m_nDesEdges);

	for (i = 1; i <= m_nDesEdges; i++)
	{
		pDE = &m_pDesEdges[i];

		//	spdlog::info("managing the edge {}.(NOD:{} ELEM:{})\n", i, m_nNodes, m_nElems);

		prevNod = pDE->iAddNodes[0];
		for (j = 1; j < pDE->nNodes - 1; j++)
		{
			currNod = pDE->iAddNodes[j];

			if (m_pNodes[currNod].iReserved >= 0)
			{
				k = j + 1;
				while (k < pDE->nNodes - 1 && m_pNodes[pDE->iAddNodes[k]].iReserved < 0)
				{
					k++;
				}
				nextNod = pDE->iAddNodes[k];

				//		spdlog::info("iNod = {}.\n", currNod);

				removeEANE(currNod, i, prevNod, nextNod);
			}
		}

#if 0
		//#ifdef _BR_MAIN_PROCEDURE_SPR #TODO1 #zyj 此处导致拓扑错误,先去掉
				//	spdlog::info("Try to removal all SPs on the edge: (NOD:{} ELEM:{})\n", m_nNodes, m_nElems);
				/* 尝试删除所有Steiner点  */
		removeEdgeSteinerPoint_SPR(i);
#endif
		nTtlSP += pDE->nNodes - 2;
		for (j = 1, nSP = 0; j < pDE->nNodes - 1; j++)
			if (m_pNodes[pDE->iAddNodes[j]].iReserved >= 0)
				nSP++;
		nRpsSP += nSP;

		if (nSP > 0)
		{
			nPartRecv++;
#ifdef _VERBOSE
			printf("Edge Recv.: %d:%d(%d-->%d)(#SP = %d) ELE:%d NOD:%d\n", nPartRecv, pDE->iEdg,
				m_pSurEdgs[pDE->iEdg].iStart - INIT_NOD_NUM + 1,
				m_pSurEdgs[pDE->iEdg].iEnd - INIT_NOD_NUM + 1,
				nSP, m_nNodes, m_nElems);
#endif
		}
		else
			nFullRecv++;

#ifdef _ERROR_CHK
		nErrCd = checkGlobalData();
		if (nErrCd != 0)
		{
			printError(nErrCd);
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;
		}
#endif
	}

	nRmvSP = nTtlSP - nRpsSP;
	spdlog::info("Results of recovering destroyed edges by removing or repositioning SPs.\n");
	spdlog::info("#Total ED:{}\t#Fully Recovered:{}\t#Partially Recovered:{}\n", m_nDesEdges, nFullRecv, nPartRecv);
	spdlog::info("#Total SP:{}\t#Removed SP:{}\t#Repositioned SP:{}\n", nTtlSP, nRmvSP, nRpsSP);
	return 1;
}

int DTIso3D::recvDesFacets()
{
	DesFacet* pDF;
	INTEGER i, iNod;
	int j;
	INTEGER nPreSP = 0, nAftSP = 0, nTtlSP = 0, nRmvSP = 0, nRpsSP = 0;
	INTEGER nFullRecv = 0, nPartRecv = 0;
	INTEGER nTtlFC = 0;

#ifdef _ERROR_CHK
	int nErrCd;
#endif /* _ERROR_CHK  */

	printf("\nRecover destroyed faces, please wait...\n");
	for (i = 1; i <= m_nDesFacets; i++)
	{
		pDF = &m_pDesFacets[i];
		for (j = 0, nPreSP = 0; j < pDF->nNodes; j++)
		{
			iNod = pDF->iAddNodes[j];
			if (m_pNodes[iNod].iReserved >= 0)
			{
				nPreSP++;
				removeEANF(iNod, i);
			}
		}
		nTtlSP += nPreSP;

		nAftSP = 0;
		if (nPreSP > 0)
		{
			nTtlFC++;
			for (j = 0; j < pDF->nNodes; j++)
			{
				iNod = pDF->iAddNodes[j];
				if (m_pNodes[iNod].iReserved >= 0)
					nAftSP++;
			}

			nRpsSP += nAftSP;
			if (nAftSP == 0)
				nFullRecv++;
			else
			{
				nPartRecv++;
#ifdef _VERBOSE

				printf("Face Recv.: %d:%d(%d->%d->%d)(#SP = %d) ELE:%d NOD:%d\n", nPartRecv, pDF->iFac + 1,
					m_pSurTris[pDF->iFac].form[0] - INIT_NOD_NUM + 1,
					m_pSurTris[pDF->iFac].form[1] - INIT_NOD_NUM + 1,
					m_pSurTris[pDF->iFac].form[2] - INIT_NOD_NUM + 1,
					nAftSP, m_nNodes, m_nElems);
#endif
			}
		}
	}

	nRmvSP = nTtlSP - nRpsSP;
	spdlog::info("Results of recovering destroyed faces by removing or repositioning SPs.\n");
	spdlog::info("#Total Faces:{}\t#Fully Recovered:{}\t#Partially Recovered:{}\n", nTtlFC, nFullRecv, nPartRecv);
	spdlog::info("#Total SP:{}\t#Removed SP:{}\t#Repositioned SP:{}\n", nTtlSP, nRmvSP, nRpsSP);

	return 1;
}

/*
* Node的iReserved域的第1位为边界节点标志,其余位表示包含节点的某个单元。
* 边界节点包括
* (1) 初始表面网格节点;
* (2) 执行一致边界恢复算法时在表面边和面片上增添的辅助点。
* The iReserved member of a Node object is divided into two parts,
* the first bit flags if the node is a boundary node, and the other
* bits index an element(tetrahedron) including the node.
* The boundary nodes is composed of both (1) nodes of the surface mesh,
* and (2) extra added in the stage of conformal boundary recovery.
 */
bool DTIso3D::isBndNode(INTEGER iNod)
{//已做修改，原始为注释部分
	/*
	#ifdef _ONE_LONG_ARRAY
	assert(iNod >= 0 && iNod < m_nNodes);
	#else
	assert(iNod >= 0 && iNod < m_pNodes.getArraySize());
	#endif
	return m_pNodes[iNod].iReserved & 0x1;
	 */
#ifdef _ONE_LONG_ARRAY
	assert(iNod >= 0 && iNod < m_nNodes);
#else
	assert(iNod >= 0 && iNod < m_pNodes.getArraySize());
#endif

#if 0
	if (((iNod >= 0 && iNod < m_nSurNodes) && !(m_pNodes[iNod].iReserved2 & (0x2))) ||
		((iNod >= m_nSurNodes) && (m_pNodes[iNod].iReserved2 & (0x2))))
	{
		printf("Error found for the boundary flag of a node: %d.flag = %d (m_nSurNode = %d).\n", iNod,
			m_pNodes[iNod].iReserved2, m_nSurNodes);
		throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;
	}
#endif

	return m_pNodes[iNod].iReserved2 & (0x2);
}

