	int DTIso3D::outVolMshZoneInfo(TigerMesh * pVolmTet)
	{
		if (!zoneInfo) return -1;
		std::shared_ptr<ZoneOutInfo> zoneout = pVolmTet->getZoneOut();
		if (!zoneout) {
			zoneout = std::make_shared<ZoneOutInfo>();
			pVolmTet->setZoneOut(zoneout);
		}
		zoneout->domain2Blocks = domain2Blocks;
		zoneout->elem2Domains = elemToDomains;
		return 0;
	}

