	int DTIso3D::countECDecre(INTEGER iNod)
	{
		if (m_pNodes[iNod].iReserved2 < (1 << 4))
		{
			spdlog::info("Error when calling countECDecre(...).\n");
			throw EXCEPTIONSTRING(std::string("error exit in") + std::string(__FILE__) + std::to_string(__LINE__));;
		}
		m_pNodes[iNod].iReserved2 -= (1 << 4);
		return m_pNodes[iNod].iReserved2 >> 4;
	}

	int DTIso3D::analyseECStatistics()
	{
		int iNod, howmany_tried = 0, howmany_removed = 0, howmany_newpnt = 0;
		int ecCount = 0;
		int nNodes;
#ifdef _ONE_LONG_ARRAY
		nNodes = m_nNodes;
#else
		nNodes = m_pNodes.getArraySize();
#endif
		for (iNod = 0; iNod < nNodes; iNod++)
		{
			ecCount = countEC(iNod);
			if (ecCount > 0)
			{
				howmany_tried++;
				if (m_pNodes[iNod].iReserved < 0)
				{
					howmany_removed++;
					if (iNod >= m_nEdgeSplitNodeStartID)
						howmany_newpnt++;
				}
			}
		}

		spdlog::info("#Callings of edge contractions and of which successful ones:({};{}).\n", g_nEdContCallings, g_nEdContCallSucc);
		spdlog::info("#Nodes of attempted and of which successfully removed:({};{}).\n", howmany_tried, howmany_removed);
		spdlog::info("#Callings for new points and of which successful ones:({};{}).\n", g_nEdContCallNewP, howmany_newpnt);

		return 0;
	}
#endif

