	int DTIso3D::smooth(int iMaxpasses, bool noQualLimit, REAL qualLimit, int qualmeasure)
	{
		int iSmoothed = 0, iTotal = 0, iPasses = 0, iTried = 0;
		int nNodes, nElems, nIdx, iNode, iElem;
		REAL cellqual[MAX_SPHERE_SIZE], qual, qvalue, worstqual;
		Sphere sph;
		int nSph = 0;
		const bool bFloatThreshold = false;

		const REAL deltaQual = 5.0 * PI / 180.0;
		REAL cosx = 0.0;
		bool bRet;
		int i, j, k, m;
		int ia, ib, ic, id;
		TetraElemQual tetEleQual, * pTetQual = nullptr;
		float q;
		int icnt, icnt_old;
		REAL fmin, faver, fmin_old, faver_old;
		Elem* pElem, * pElemIt;
		MeshElment mshElm;

#ifdef _TIMING_PERFORMANCE
		time_start[MESH_SMOOTHING_TIME] = SPRlogTime();
#endif

		spdlog::info("Smoothing is started.\n");
		evalMesh(&icnt_old, &fmin_old, &faver_old, qualmeasure, qualLimit);

		while (iPasses < iMaxpasses)
		{
			++iPasses;
			iSmoothed = 0;
			iTried = 0;

			assert(m_elmHeap->isEmpty());

#ifdef _ONE_LONG_ARRAY
			nElems = m_nElems;
#else
			nElems = m_pElems.getArraySize();
#endif

			/* 根据globalMinQual调整qualLimit的值  */
			assert(globalMinQual >= 0.0);
			if (bFloatThreshold && globalMinQual <= 1.0)
			{
				cosx = sqrt(1.0 - globalMinQual * globalMinQual);
				qualLimit = MIN_VALUE(qualLimit, (globalMinQual + deltaQual * cosx));
				spdlog::info("GlobalMin = {}; Qual. Limit = {}.\n", globalMinQual, qualLimit);
			}

			for (i = 0; i < nElems; i++)
			{
				if (isDelEle(&m_pElems[i]))
					continue;

				tetEleQual = m_tetraElmQuals[i];
				q = tetEleQual.sinValue;

				if (q >= qualLimit)
					continue;

				mshElm.Elem = i;
				mshElm.elmQual = &m_tetraElmQuals[i];

				m_elmHeap->insertElem(mshElm);
			}
			//		spdlog::info("#Poor Elements;{}\n", m_elmHeap->heapSize());
			clock_t t1 = clock();
			while (!m_elmHeap->isEmpty())
			{
				mshElm = m_elmHeap->getMinElem();
				iElem = mshElm.Elem;
				this->curSwapElm = iElem;
				pElem = &m_pElems[iElem];

				assert(!isDelEle(pElem));
				m_elmHeap->rmMinElem();

				for (i = 0; i <= DIM; i++)
				{
					iNode = pElem->form[i];

					//过滤掉边界网格点和wellshaped网格点
					if (isBndNode(iNode) || isNodeWellShaped(iNode) || m_pNodes[iNode].iReserved < 0)
						continue;

					if (isNodeSmoothed(iNode))
						continue;

					//标记该点为wellshaped
					setNodeWellShaped(iNode);
					findSphere(iNode, sph, &nSph);
					worstqual = 1.0e20;
					for (k = 0; k < nSph; k++)
					{
						tetEleQual = m_tetraElmQuals[sph[k]];
						q = tetEleQual.sinValue;

						if (q < worstqual)
							worstqual = q;
					}

					/* 浮动最小值  */
		//			if (globalMinQual > worstqual)
		//				globalMinQual = worstqual;

					if (!noQualLimit && worstqual >= qualLimit)
						continue;

					iTried++;
					g_nGlobalSmoothingCallings++;
					try {
						bRet = combinedSmoothing(iNode, sph, nSph, true/*true */, worstqual, qualLimit, &qual, cellqual, qualmeasure);
					}
					catch (std::exception e) {
						continue;
					};
					if (bRet /*&& isMeshBetter(num_tet, cells, cellqual, 30.0) */)
					{
						g_nGlobalSmoothingCallSucc++;
						if (qual < qualLimit)
						{
							//标记该点为illshaped，同时标记该点相连的边为需要优化的边
							setNodeIllShaped(iNode);
							for (j = 0; j < nSph; j++)
							{
								qvalue = cellqual[j];
								if (qvalue < qualLimit)
								{
									pElemIt = &m_pElems[sph[j]];
									//标记该单元的所有点都为illshaped
									for (m = 0; m <= DIM; m++)
									{
										setNodeIllShaped(pElemIt->form[m]);
									}
								}
							}
						}

						for (j = 0; j < nSph; j++)
						{
							pElemIt = &m_pElems[sph[j]];
							//标记该单元的所有点都为illshaped
							for (m = 0; m <= DIM; m++)
							{
								disableNodeSmoothed(pElemIt->form[m]);
								disableSuppressionTried(pElemIt->form[m]);
							}
						}
						enableNodeSmoothed(iNode);// however, the current node is smoothed

#if 0
						//update cells qual
						updateMeshQual(nSph, sph, cellqual);
#else
						for (j = 0; j < nSph; j++)
						{
							pTetQual = &m_tetraElmQuals[sph[j]];
							pTetQual->sinValue = cellqual[j];
							pTetQual->iReserved = 0;
						}
#endif

						/* 浮动最小值  */
						if (globalMinQual > qual)
							globalMinQual = qual;

						iSmoothed++;
					}
					else
					{
						setNodeIllShaped(iNode);
						enableNodeSmoothed(iNode);//the node is smoothed yet  */
					}
				} /* for (i = 0; i <= DIM; i++)  */
			}

			iTotal += iSmoothed;

			printf("	Pass %d:  %5d vertices moved by smoothing, %6d tried.\n", iPasses, iSmoothed, iTried);
			if (iSmoothed > 0)
			{
				evalMesh(&icnt, &fmin, &faver, qualmeasure, qualLimit);

				if (icnt < icnt_old && fmin >= fmin_old && faver >= faver_old) /* 比上次优化有改进  */
				{
					icnt_old = icnt;
					fmin_old = fmin;
					faver_old = faver;
				}
				else
					break;
			}
			else
				break;
		}

#ifdef _TIMING_PERFORMANCE
		time_final[MESH_SMOOTHING_TIME] = SPRlogTime();
		time_elaps[MESH_SMOOTHING_TIME] += time_final[MESH_SMOOTHING_TIME] - time_start[MESH_SMOOTHING_TIME];
#endif

		return iTotal;
	}
#endif
	void DTIso3D::flagdepfacenode(int a, int b, int* faceNodesDep, int* faceNodes, int faceNum, InstEntList & listDependentEnts)
	{
		int i, depNodeCnt = 0, iOther, indices[3];
		int iEntDep = listDependentEnts.getFirstEnt();
		while (iEntDep > 0)
		{
			if (listDependentEnts.isActive(iEntDep))
			{
				listDependentEnts.nodeIndices(iEntDep, indices);
				iOther = -1;
				if (indices[0] == a || indices[0] == b)
					iOther = indices[1];
				else if (indices[1] == a || indices[1] == b)
					iOther = indices[0];
				if (iOther >= 0)
				{/* 0是有效的索引  */
					for (i = 0; i < faceNum; i++)
						if (faceNodes[i] == iOther)
						{
							faceNodesDep[i] = 1;
							depNodeCnt++;
							break;
						}
				}
			}
			iEntDep = listDependentEnts.getNextEnt(iEntDep);
		}
		assert(depNodeCnt <= m_nMaxInflationLevel);
	}
