	void DTIso3D::getshellqual(int a, int b, Shell she, int nShe, float* qual)
	{
		int i, iElm;
		float val, minVal;

		minVal = 1.0;
		for (i = 0; i < nShe; i++)
		{
			iElm = she[i];

			val = m_tetraElmQuals[iElm].sinValue;
			if (val < minVal)
				minVal = val;
		}

		*qual = minVal;
	}
