	//获得壳单元质量（为壳中所有单元质量的最小值）
	void DTIso3D::getshellqual(int a, int b, Shell she, int nShe, float* qual)
	{
		int i, j, k, nele, ilast, eIdx;
		int p, p1, p2, ep[2], faceNodes[MAX_SKIRT_POLY_SIZE];
		int faceNum, facePrts[2 * MAX_SKIRT_POLY_SIZE];
		float tetsqual[MAX_SKIRT_POLY_SIZE], onetetqual[6], qvalue;

		Elem ele = m_pElems[she[0]];

		for (i = 0; i <= DIM; i++)
		{
			if (ele.form[i] != a && ele.form[i] != b)
			{
				p = ele.form[i];
				break;
			}
		}

		//注意facdNodes[m]/faceNodes[(m+1)%faceNum]/ep[0]/ep[1]为正体积方向
		findShellFaces_InOrder(a, b, she[0], p, faceNodes, facePrts, &faceNum);
		assert(faceNum == nShe);
		if (faceNum > MAX_SKIRT_POLY_SIZE)
		{
			spdlog::info("Error:Shell is too large! \n");
			return;
		}

		//计算质量
		for (k = 0; k < faceNum; k++)
		{
			qvalue = tetqual(faceNodes[k], faceNodes[(k + 1) % faceNum], a, b, onetetqual, DIHEDRAL_ANGLE_SINE);
			if (k == 0)
				*qual = qvalue;
			if (qvalue < *qual)
				*qual = qvalue;
		}
	}
