	void DTIso3D::getshellqual(Shell she, int nShe, float qualArray[])
	{
		int i, iElm;

		for (i = 0; i < nShe; i++)
		{
			iElm = she[i];
			qualArray[i] = m_tetraElmQuals[iElm].sinValue;
		}
		::qsort(qualArray, nShe, sizeof(float), compareFloatValues);
	}

