					if (((q1 = tetqual(a, faceNodes[0], faceNodes[1], faceNodes[2], nullptr, bAcute, DIHEDRAL_ANGLE_SINE)) < qold + eps) ||
						((q2 = tetqual(faceNodes[0], faceNodes[1], faceNodes[2], b, nullptr, bAcute, DIHEDRAL_ANGLE_SINE)) < qold + eps))
						bSwap32Valid = false;
#else
